package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelKostenplaatsKey2;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ArtikelBedrag;
import be.schaubroeck.lpb.tools.ArtikelHoofd;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.RekenOverdracht;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.criteria.Criterium;
import be.schaubroeck.lpb.tools.enumtypes.AardRekenelement;
import be.schaubroeck.lpb.tools.enumtypes.BoekingType;
import be.schaubroeck.lpb.tools.enumtypes.RekenHoofdBron;
import be.schaubroeck.lpb.tools.jpa.lo.ArtikelBedragPO;
import be.schaubroeck.lpb.tools.jpa.lo.ArtikelHoofdPO;
import be.schaubroeck.lpb.tools.jpa.lo.RekenBedragPO;
import be.schaubroeck.lpb.tools.jpa.lo.RekenHoofdPO;
import be.schaubroeck.lpb.tools.jpa.lo.RekenLijnPO;
import be.schaubroeck.lpb.tools.jpa.lo.RekenOverdrachtPO;
import be.schaubroeck.lpb.tools.service.ConstantService;
import be.schaubroeck.lpb.tools.service.RekenResultatenService;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Qualifier;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

public class StandaardTegenBoekenSnummerService implements TegenBoekenSnummerService {

    @Autowired
    private RekenResultatenService rekenResultatenService;

    @Autowired
    @Qualifier("cachedConstantService")
    private ConstantService constantService;

    @Override
    @InitializeAdmin
    public void tegenBoeken(Admin admin, Integer snummer, RekenTijd rekenTijd) {
        List<RekenHoofd> bestaanden = getRekenResultatenBySnummerBatched(admin, snummer);
        TimeTools timeTools = new TimeTools(admin, constantService);
        Integer boekJaar = timeTools.bepaalBoekJaar(rekenTijd);
        List<RekenHoofd> tegenBoekingen = new ArrayList<>();
        for (RekenHoofd rekenHoofd : bestaanden) {
            RekenHoofd antiRekenHoofd = maakRekenHoofd(rekenHoofd, rekenTijd);
            tegenBoekingen.add(antiRekenHoofd);
            ArtikelHoofd antiArtikelHoofd = maakArtikelHoofd(antiRekenHoofd, rekenTijd, boekJaar);
            antiRekenHoofd.addArtikelHoofd(antiArtikelHoofd);
            for (RekenLijn rekenLijn : rekenHoofd.getRekenLijnen()) {
                RekenLijn antiLijn = maakRekenLijn(rekenLijn, AardRekenelement.TEGENBOEKING);
                antiRekenHoofd.addRekenLijn(antiLijn);
                for (RekenBedrag rekenBedrag : rekenLijn.getRekenBedragen()) {
                    RekenBedrag antiRekenBedrag = maakInversRekenBedrag(rekenBedrag);
                    antiLijn.addRekenBedrag(antiRekenBedrag);
                    MoneyMap<ArtikelKostenplaatsKey2> artikelMap = new HashMoneyMap<>();
                    for (ArtikelBedrag artikelBedrag : rekenBedrag.getArtikelBedragen()) {
                        artikelMap.addToMoney(new ArtikelKostenplaatsKey2(artikelBedrag.getArtikel(), artikelBedrag.getKostenplaats()),
                                artikelBedrag.getBedrag());
                    }
                    for (ArtikelKostenplaatsKey2 key : artikelMap.keySet()) {
                        Money bedrag = artikelMap.getMoney(key).negate();
                        if (bedrag.signum() != 0) {
                            ArtikelBedrag antiArtikelBedrag = maakArtikelBedrag(key, bedrag, antiRekenBedrag, antiArtikelHoofd);
                            antiRekenBedrag.getArtikelBedragen().add(antiArtikelBedrag);
                            antiArtikelHoofd.addArtikelBedrag(antiArtikelBedrag);
                        }
                    }
                }
            }
            for (RekenOverdracht bestaandeOverdracht : rekenHoofd.getRekenOverdrachten()) {
                antiRekenHoofd.addRekenOverdracht(maakInversRekenOverdracht(bestaandeOverdracht));
            }
        }
        rekenResultatenService.create(admin, tegenBoekingen);
    }

    private static final String REKENRESULTATEN_MET_ARTIKEL_WEERGAVE_FETCH_STRING =
            "rekenLijnen{aardKodeExtensie,rekenBedragen{artikelBedragen{artikel}},rekenInfos},rekenOverdrachten,artikelHoofden";
    private static final Integer BATCH_SIZE = 1000;

    private List<RekenHoofd> getRekenResultatenBySnummerBatched(Admin admin, Integer snummer) {
        List<RekenHoofd> rekenHoofden = getRekenResultatenBySnummerNaive(admin, snummer, "");
        List<Set<Integer>> listOfSetsOfRekenHoofdIds = new ArrayList<>();
        Set<Integer> rekenHoofdIds = new HashSet<>();
        listOfSetsOfRekenHoofdIds.add(rekenHoofdIds);
        for (RekenHoofd hoofd : rekenHoofden) {
            if (rekenHoofdIds.size() > BATCH_SIZE) {
                rekenHoofdIds = new HashSet<>();
                listOfSetsOfRekenHoofdIds.add(rekenHoofdIds);
            }
            rekenHoofdIds.add(hoofd.getId());
        }
        List<RekenHoofd> rekenHoofdenFetched = new ArrayList<>();
        for (Set<Integer> set : listOfSetsOfRekenHoofdIds) {
            CriteriaBuilder cb = new CriteriaBuilder();
            cb.and("id", Criterium.IN(set));
            cb.fetch(REKENRESULTATEN_MET_ARTIKEL_WEERGAVE_FETCH_STRING);
            rekenHoofdenFetched.addAll(rekenResultatenService.findByCriteria(admin, cb));
        }
        return rekenHoofdenFetched;
    }

    private List<RekenHoofd> getRekenResultatenBySnummerNaive(Admin admin, Integer snummer, String fetchString) {
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.and("artikelHoofden.snummer", Criterium.EQ(snummer));
        cb.fetch(fetchString);
        return rekenResultatenService.findByCriteria(admin, cb);
    }

    private RekenHoofd maakRekenHoofd(RekenHoofd bestaand, RekenTijd rekenTijd) {
        RekenHoofd rekenHoofd = new RekenHoofdPO();
        rekenHoofd.setOpdracht(bestaand.getOpdracht());
        rekenHoofd.setBeginDatum(bestaand.getBeginDatum());
        rekenHoofd.setEindDatum(bestaand.getEindDatum());
        rekenHoofd.setRekenTijdstip(rekenTijd.rekenTijdstip);
        rekenHoofd.setRekenDatum(rekenTijd.rekenDatum);
        rekenHoofd.setBeslagDatum(bestaand.getBeslagDatum());
        rekenHoofd.setJaar(bestaand.getJaar());
        rekenHoofd.setKwartaal(bestaand.getKwartaal());
        rekenHoofd.setFiscaalJaar(bestaand.getFiscaalJaar());
        rekenHoofd.setAchterstal(bestaand.getAchterstal());
        rekenHoofd.setRekenModus(bestaand.getRekenModus());

        rekenHoofd.setRekenGroep(bestaand.getRekenGroep());
        rekenHoofd.setHoedanigheid(bestaand.getHoedanigheid());
        rekenHoofd.setCategorie(bestaand.getCategorie());
        rekenHoofd.setWerkgeversCategorie(bestaand.getWerkgeversCategorie());
        rekenHoofd.setWerknemersKengetal(bestaand.getWerknemersKengetal());
        rekenHoofd.setPensioenStelsel(bestaand.getPensioenStelsel());
        rekenHoofd.setBron(RekenHoofdBron.REKENMOTOR2);
        rekenHoofd.setRekenLijnen(new HashSet<>());
        rekenHoofd.setRekenOverdrachten(new HashSet<>());
        return rekenHoofd;
    }

    private RekenLijn maakRekenLijn(RekenLijn bestaand, AardRekenelement typeBoeking) {
        RekenLijn lijn = new RekenLijnPO();
        lijn.setBeginDatum(bestaand.getBeginDatum());
        lijn.setEindDatum(bestaand.getEindDatum());
        lijn.setAardKodeExtensie(bestaand.getAardKodeExtensie());
        lijn.setRegimeBv(bestaand.getRegimeBv());
        lijn.setRekenBedragen(new HashSet<>());
        lijn.setRekenInfos(new HashSet<>());
        lijn.setReferentieJaar(bestaand.getReferentieJaar());
        lijn.setTypeBoeking(typeBoeking);
        return lijn;
    }

    private RekenBedrag maakInversRekenBedrag(RekenBedrag bestaand) {
        RekenBedrag rekenBedrag = new RekenBedragPO();
        rekenBedrag.setBedragType(bestaand.getBedragType());
        rekenBedrag.setBedrag(bestaand.getBedrag().negate());
        rekenBedrag.setArtikelBedragen(new HashSet<>());
        return rekenBedrag;
    }

    private RekenOverdracht maakInversRekenOverdracht(RekenOverdracht bestaand) {
        RekenOverdracht overdracht = new RekenOverdrachtPO();
        overdracht.setOpdracht(bestaand.getOpdracht());
        overdracht.setBeginDatum(bestaand.getBeginDatum());
        overdracht.setRegimeBv(bestaand.getRegimeBv());
        overdracht.setBedragType(bestaand.getBedragType());
        overdracht.setBedrag(bestaand.getBedrag().negate());
        return overdracht;
    }

    private ArtikelHoofd maakArtikelHoofd(RekenHoofd rekenHoofd, RekenTijd rekenTijd, Integer boekJaar) {
        ArtikelHoofd artikelHoofd = new ArtikelHoofdPO();
        artikelHoofd.setRekenHoofd(rekenHoofd);
        artikelHoofd.setArtikelTijdstip(rekenTijd.rekenTijdstip);
        artikelHoofd.setBoekDatum(rekenTijd.boekDatum);
        artikelHoofd.setBoekJaar(boekJaar);
        return artikelHoofd;
    }

    private ArtikelBedrag maakArtikelBedrag(ArtikelKostenplaatsKey2 key, Money bedrag, RekenBedrag rekenBedrag, ArtikelHoofd artikelHoofd) {
        ArtikelBedrag artikelBedrag = new ArtikelBedragPO();
        artikelBedrag.setRekenBedrag(rekenBedrag);
        artikelBedrag.setArtikelHoofd(artikelHoofd);
        artikelBedrag.setArtikel(key.getArtikel());
        artikelBedrag.setBoekingType(BoekingType.TEGENBOEKING);
        artikelBedrag.setBedrag(bedrag);
        artikelBedrag.setKostenplaats(key.getKostenplaats());
        return artikelBedrag;
    }
}
